void Warrior::init(int __nColor, int __nKind, int __nID, int nRemainHP)
{
    nColor  = __nColor;
    nKind   = __nKind;
    nID     = __nID;
    nHP     = WarriorHP[nKind];
    nAttack = WarriorAttack[nKind];
    if (nKind == 0)   // dragon
    {
        int nArmKind = nID % ArmKinds;
        if (nArmKind == 0)
            nArms[0].nAttack = nAttack * 0.2;   // ①
        else if (nArmKind == 1)
            nArms[1].nTimes = 1;                // ②
        else
            nArms[2].nTimes = 3;                // ③
        nMorale = (double)nRemainHP / nHP;      // ④
    }
    else if (nKind == 1)  // ninja（拿两件）
    {
        int nArmKind = nID % ArmKinds;
        if      (nArmKind == 0) { nArms[0].nAttack = nAttack * 0.2; nArms[1].nTimes = 1; }
        else if (nArmKind == 1) { nArms[1].nTimes  = 1;             nArms[2].nTimes = 3; }
        else                    { nArms[2].nTimes  = 3; nArms[0].nAttack = nAttack * 0.2; }
    }
    else if (nKind == 2)  // iceman（同 dragon，拿一件）
    {
        int nArmKind = nID % ArmKinds;
        if      (nArmKind == 0) nArms[0].nAttack = nAttack * 0.2;
        else if (nArmKind == 1) nArms[1].nTimes  = 1;
        else                    nArms[2].nTimes   = 3;
    }
    --snip--

