void Warrior::PrintBornInfo(int hour)
{
    printf("%03d:00 %s %s %d born\n", hour, ColorName[nColor], WarriorName[nKind], nID);
    if (nKind == 0)
        printf("Its morale is %.02f\n", nMorale);   // ②
