void City::SetWin(int i, int hour, int id)
{
    if (i == -1)          // ①
    {
        nWin = -1;
        return;
    }
    if (nFlag == -1 && nWin == -1)   // ②
    {
        nWin = i;
        return;
    }
    if (nFlag != i && nWin == i)     // ③
    {
        nFlag = i;
        printf("%03d:40 %s flag raised in city %d\n", hour, ColorName[i], id);
        return;
    }
    nWin = i;   // ④
}

