void HeadQuarter::Produce(int nHour)
{
    int i = Order[nColor][nTotalWarrior % WarriorKinds];   // ①
    if (WarriorHP[i] > nTotalHP)
    {
        nCurWarrior = -1;   // ②
        return;
    }
    nTotalHP -= WarriorHP[i];
    Warrior nw;
    nw.init(nColor, i, nTotalWarrior + 1, nTotalHP);       // ③
    nw.PrintBornInfo(nHour);
    w.push_back(nw);
    nCurWarrior   = nTotalWarrior;                         // ④
    nTotalWarrior++;
}

