void BombPhase(int hour)
{
    int nID[2];
    for (int i = 1; i <= N; i++)
    {
        nID[0] = mCity[i].nWid[0];  nID[1] = mCity[i].nWid[1];
        if (nID[0] < 0 || nID[1] < 0) continue;
        if (head[0].w[nID[0]].nHP <= 0 || head[1].w[nID[1]].nHP <= 0) continue;
        for (int j = 0; j < 2; j++)
        {
            if (head[j].w[nID[j]].nArms[1].nTimes > 0)   // j has bomb
            {
                if (mCity[i].nFlag == j ||
                    (mCity[i].nFlag == -1 && i % 2 == 1 - j))   // ①  j attacks first
                {
                    if (head[1-j].w[nID[1-j]].nHP >                  // ②  cannot kill enemy
                            (head[j].w[nID[j]].nAttack +
                             head[j].w[nID[j]].nArms[0].nAttack))
                        if (head[1-j].w[nID[1-j]].nKind != 1)        // ③  enemy not ninja
                            if (head[j].w[nID[j]].nHP <=             // ④  will be killed
                                    (head[1-j].w[nID[1-j]].nAttack / 2 +
                                     head[1-j].w[nID[1-j]].nArms[0].nAttack))
                            {
                                printf("%03d:38 %s %s %d used a bomb and killed %s %s %d\n", ...);
                                head[j].w[nID[j]].nHP      = 0;
                                head[1-j].w[nID[1-j]].nHP  = 0;
                                continue;
                            }
                }
                else   // j attacks second, full enemy attack (not halved)
                {
                    if (head[j].w[nID[j]].nHP <=
                            (head[1-j].w[nID[1-j]].nAttack +
                             head[1-j].w[nID[1-j]].nArms[0].nAttack))   // ⑤
                    {
                        printf("%03d:38 %s %s %d used a bomb and killed %s %s %d\n", ...);
                        head[j].w[nID[j]].nHP = 0;  head[1-j].w[nID[1-j]].nHP = 0;
                        continue;
                    }
                }
            }
        }
    }
}

