void run()
{
    cin >> M >> N >> R >> K >> T;   // ①
    int i;
    for (i = 0; i < WarriorKinds; i++) cin >> WarriorHP[i];
    for (i = 0; i < WarriorKinds; i++) cin >> WarriorAttack[i];
    for (i = 0; i <= 21; i++) mCity[i].init();
    head[0].init(M, 0);
    head[1].init(M, 1);
    int nHour = 0;
    i = 0;
    while (true)
    {
        int cur_time = nHour * 60 + WorkMinute[i];
        if (cur_time > T) break;       // ②
        TimeProc(nHour, i);
        if (i == 2)                    // ③
        {
            if (head[0].nEnemy >= 2 || head[1].nEnemy >= 2) break;
        }
        i++;
        if (i == MinuteType) { i = 0; nHour++; }
    }
}

void work()
{
    int nCase;
    cin >> nCase;
    for (int i = 1; i <= nCase; i++) { printf("Case %d:\n", i); run(); }
}

int main() { work(); return 0; }
